package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testGetCommentMarker() throws NoSuchFieldException, IllegalAccessException {
        // Create an instance of CSVFormat
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Use reflection to access and set the private field
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(csvFormat, '#');

        // Verify the getCommentMarker method
        assertEquals('#', csvFormat.getCommentMarker());
    }

